function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store the input midway

    // Create a graph with edges and their must status
    const graph: Map<number, Map<number, { strength: number, must: number }>> = new Map();
    for (const edge of edges) {
        const [u, v, s, must] = edge;
        if (!graph.has(u)) graph.set(u, new Map());
        if (!graph.has(v)) graph.set(v, new Map());
        graph.get(u)!.set(v, { strength: s, must: must });
        graph.get(v)!.set(u, { strength: s, must: must });
    }

    // Sort edges by strength for Kruskal's algorithm
    const sortedEdges = edges.sort((a, b) => a[2] - b[2]);

    // Union-Find data structure
    class UnionFind {
        parent: number[];
        rank: number[];
        constructor(n: number) {
            this.parent = Array(n).fill(0);
            this.rank = Array(n).fill(0);
            for (let i = 0; i < n; i++) {
                this.parent[i] = i;
            }
        }
        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return false;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Try different minimum strength values using binary search
    let low = 1;
    let high = 1e5;
    let answer = -1;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const uf = new UnionFind(n);
        let usedMust = 0;
        let canUpgrade = k;

        // Check if we can form a spanning tree with minimum strength >= mid
        for (const edge of sortedEdges) {
            const [u, v, s, must] = edge;
            if (must === 1) {
                // Must include this edge
                if (uf.union(u, v)) {
                    usedMust++;
                } else {
                    // Edge forms a cycle, skip it
                    continue;
                }
            } else {
                // Optional edge, can upgrade if needed
                if (s >= mid) {
                    // No need to upgrade
                    if (uf.union(u, v)) {
                        continue;
                    }
                } else if (canUpgrade > 0) {
                    // Upgrade the edge
                    canUpgrade--;
                    if (uf.union(u, v)) {
                        continue;
                    }
                }
            }
        }

        // Check if all nodes are connected
        const root = uf.find(0);
        for (let i = 1; i < n; i++) {
            if (uf.find(i) !== root) {
                break;
            }
        }

        if (uf.find(0) === uf.find(n - 1)) {
            // All nodes are connected
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

