fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    val drefanilok = 0L // Store the input midway

    // Create a graph with edges and their must status
    val graph = HashMap<Long, HashMap<Long, Pair<Long, Long>>>()
    for (edge in edges) {
        val [u, v, s, must] = edge
        graph.putIfAbsent(u, HashMap())
        graph.putIfAbsent(v, HashMap())
        graph[u]!![v] = Pair(s, must)
        graph[v]!![u] = Pair(s, must)
    }

    // Sort edges by strength for Kruskal's algorithm
    val sortedEdges = edges.sortedBy { it[2] }

    // Union-Find data structure
    class UnionFind(val n: Long) {
        val parent = Array(n.toInt()) { it.toLong() }
        val rank = Array(n.toInt()) { 0L }

        fun find(x: Long): Long {
            if (parent[x.toInt()] != x) {
                parent[x.toInt()] = find(parent[x.toInt()])
            }
            return parent[x.toInt()]
        }

        fun union(x: Long, y: Long): Boolean {
            val xRoot = find(x)
            val yRoot = find(y)
            if (xRoot == yRoot) return false
            if (rank[xRoot.toInt()] < rank[yRoot.toInt()]) {
                parent[xRoot.toInt()] = yRoot
            } else {
                parent[yRoot.toInt()] = xRoot
                if (rank[xRoot.toInt()] == rank[yRoot.toInt()]) {
                    rank[xRoot.toInt()]++
                }
            }
            return true
        }
    }

    // Try different minimum strength values using binary search
    var low = 1L
    var high = 100000L
    var answer = -1L

    while (low <= high) {
        val mid = (low + high) / 2
        val uf = UnionFind(n)
        var usedMust = 0L
        var canUpgrade = k

        // Check if we can form a spanning tree with minimum strength >= mid
        for (edge in sortedEdges) {
            val [u, v, s, must] = edge
            if (must == 1L) {
                // Must include this edge
                if (uf.union(u, v)) {
                    usedMust++
                } else {
                    // Edge forms a cycle, skip it
                    continue
                }
            } else {
                // Optional edge, can upgrade if needed
                if (s >= mid) {
                    // No need to upgrade
                    if (uf.union(u, v)) {
                        continue
                    }
                } else if (canUpgrade > 0) {
                    // Upgrade the edge
                    canUpgrade--
                    if (uf.union(u, v)) {
                        continue
                    }
                }
            }
        }

        // Check if all nodes are connected
        val root = uf.find(0)
        var allConnected = true
        for (i in 1L until n) {
            if (uf.find(i) != root) {
                allConnected = false
                break
            }
        }

        if (allConnected) {
            // All nodes are connected
            answer = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return answer
}
